import { Resource } from '@/models/resource';
import { Session } from '@/models/session';
import { Team } from '@/models/team';
import { User } from '@/models/user';
import { translate } from '@/utils/i18n';

type Availability = { isAvailable: boolean; unavailableReason: string | null };

export const checkAnalysisAvailability = (
  session: Session,
  user: User,
  team: Team,
): Availability => {
  if (!user.hasBasicWriteAccessFor(session)) {
    return {
      isAvailable: false,
      unavailableReason: translate(
        'insufficient_permission_for_analyzing_video',
      ),
    };
  }
  if (!team.teamPlanAvailability.isAvailable) {
    return {
      isAvailable: false,
      unavailableReason: translate(
        team.teamPlanAvailability.unavailableReason!,
      ),
    };
  }
  return {
    isAvailable: true,
    unavailableReason: null,
  };
};

export const checkReanalysisAvailability = (
  resource: Resource,
  user: User,
  team: Team,
): Availability => {
  if (!resource.canReanalyze) {
    return { isAvailable: false, unavailableReason: null };
  }
  if (!user.hasBasicWriteAccessFor(resource, team.id)) {
    return {
      isAvailable: false,
      unavailableReason: translate(
        'insufficient_permission_for_analyzing_video',
      ),
    };
  }
  if (!team.teamPlanAvailability.isAvailable) {
    return {
      isAvailable: false,
      unavailableReason: translate(
        team.teamPlanAvailability.unavailableReason!,
      ),
    };
  }
  return {
    isAvailable: true,
    unavailableReason: null,
  };
};

