#### 1. `web/src/models/team.ts`

##### 1.1 `teamPlanAvailability` getter гҒ®дҝ®жӯЈ

**еӨүжӣҙеүҚпјҲ93-112 иЎҢзӣ®пјүпјҡ**
```typescript
get teamPlanAvailability(): {
  isAvailable: boolean;
  unavailableReason: TranslationKey | null;
} {
  const isRateLimitReached = this.ballRate >= 1;  // дҪҝз”ЁзҺҮгғҒгӮ§гғғгӮҜ
  const isExpired = this.remainingDays <= 0;      // жңҹйҷҗгғҒгӮ§гғғгӮҜ
  if (isRateLimitReached || isExpired) {
    return {
      isAvailable: false,
      unavailableReason: isExpired
        ? this.nextTeamPlan?.isPendingActivation
          ? 'next_team_plan_has_not_started_yet'
          : this.teamPlan
            ? 'team_plan_expired'
            : 'no_team_plan_found'
        : 'you_have_reached_usage_limit',
    };
  }
  return {
    isAvailable: true,
    unavailableReason: null,
  };
}
```

**еӨүжӣҙеҫҢпјҡ**
```typescript
