   214вҶ’
   215вҶ’  // AI гӮігғјгғҒеҲ©з”ЁеҸҜпјҲиӯҰе‘ҠгҒӮгӮҠпјү
   216вҶ’  limitApproaching, // дёҠйҷҗжҺҘиҝ‘пјҲcurrentAiCoachUsage >= maxAiCoachs * 0.9пјү
   217вҶ’
   218вҶ’  // AI гӮігғјгғҒеҲ©з”ЁеҸҜпјҲжӯЈеёёпјү
   219вҶ’  ok,
   220вҶ’  ;
   221вҶ’
   222вҶ’  /// AI гӮігғјгғҒеҲ©з”ЁеҸҜиғҪгҒӢгҒ©гҒҶгҒӢ
   223вҶ’  bool get canUseAiCoach => this == limitApproaching || this == ok;
   224вҶ’}
