 * гғҒгғјгғ гғ—гғ©гғігҒ®еҘ‘зҙ„гғ»жңүеҠ№жңҹйҷҗгҒ«й–ўгҒҷгӮӢзҠ¶ж…Ӣ
 * Flutter гҒ® TeamPlanStatus гҒ«еҜҫеҝң
 */
export enum TeamPlanStatus {
  NO_CONTRACT = 'no_contract',        // жңүж–ҷгғ—гғ©гғіеҘ‘зҙ„гҒӘгҒ—
  NEXT_PLAN_PENDING = 'next_plan_pending',  // ж¬Ўеӣһгғ—гғ©гғігҒҢдҝқз•ҷдёӯ
  EXPIRED = 'expired',                // жңҹйҷҗеҲҮгӮҢ
  EXPIRING_SOON = 'expiring_soon',    // 30ж—Ҙд»ҘеҶ…гҒ«жңҹйҷҗеҲҮгӮҢ
  OK = 'ok',                          // жӯЈеёё
}

/**
 * гғңгғјгғ«и§ЈжһҗгҒ®дҪҝз”ЁйҮҸзҠ¶ж…Ӣ
 * Flutter гҒ® BallAnalysisUsageStatus гҒ«еҜҫеҝң
 */
export enum BallUsageStatus {
  LIMIT_REACHED = 'limit_reached',      // дёҠйҷҗеҲ°йҒ”
  LIMIT_APPROACHING = 'limit_approaching',  // дёҠйҷҗжҺҘиҝ‘пјҲ90%д»ҘдёҠпјү
  OK = 'ok',                            // жӯЈеёё
}

/**
 * AI гӮігғјгғҒгҒ®дҪҝз”ЁйҮҸзҠ¶ж…Ӣ
 * Flutter гҒ® AICoachUsageStatus гҒ«еҜҫеҝң
 */
export enum AiCoachUsageStatus {
  LIMIT_REACHED = 'limit_reached',
  LIMIT_APPROACHING = 'limit_approaching',
  OK = 'ok',
}

// Helper functions
export const teamPlanStatusIsValid = (status: TeamPlanStatus): boolean => {
  return status === TeamPlanStatus.EXPIRING_SOON || status === TeamPlanStatus.OK;
};

export const ballUsageStatusCanAnalyze = (status: BallUsageStatus): boolean => {
  return status === BallUsageStatus.LIMIT_APPROACHING || status === BallUsageStatus.OK;
};

export const ballUsageStatusShouldWarn = (status: BallUsageStatus): boolean => {
  return status === BallUsageStatus.LIMIT_APPROACHING;
};

export const aiCoachUsageStatusCanUse = (status: AiCoachUsageStatus): boolean => {
  return status === AiCoachUsageStatus.LIMIT_APPROACHING || status === AiCoachUsageStatus.OK;
};
