   get maxBalls(): number {
     if (!this.teamPlan && !this.item) return 0;
     const planMax = this.teamPlanAvailability.isAvailable
       ? this.teamPlan?.plan.maxBalls ?? 0 : 0;
     const itemMax = this.item?.ballAvailableCount ?? 0;
     return planMax + itemMax;
   }

   // Status getters (Flutter enum-based)
   get teamPlanStatus(): TeamPlanStatus {
     if (!this.teamPlan || this.teamPlan.isActive !== true) {
       return TeamPlanStatus.NO_CONTRACT;
     }
     const isExpired = this.remainingDays <= 0;
     if (isExpired) {
       if (this.nextTeamPlan?.isPendingActivation === true) {
         return TeamPlanStatus.NEXT_PLAN_PENDING;
       }
       return TeamPlanStatus.EXPIRED;
     }
     if (this.remainingDays <= 30) {
       return TeamPlanStatus.EXPIRING_SOON;
     }
     return TeamPlanStatus.OK;
   }

   get ballUsageStatus(): BallUsageStatus {
     const usage = this.ballUsage;
     const maxUsage = this.maxBalls;
     if (usage >= maxUsage) return BallUsageStatus.LIMIT_REACHED;
     if (usage >= Math.floor(maxUsage * 0.9)) return BallUsageStatus.LIMIT_APPROACHING;
     return BallUsageStatus.OK;
   }

   // Boolean convenience getters (Flutter API)
