   421вҶ’                        onClick={closeDrawerOnSmallScreen}
   422вҶ’                      >
   423вҶ’                        <ListItemButton
   424вҶ’                          selected={!!x.isSelected}
   425вҶ’                          sx={{
   426вҶ’                            justifyContent: 'center',
   427вҶ’                          }}
   428вҶ’                        >
   429вҶ’                          <ListItemIcon
   430вҶ’                            sx={{
   431вҶ’                              minWidth: 0,
   432вҶ’                              mr: open ? 3 : 'auto',
   433вҶ’                              justifyContent: 'center',
   434вҶ’                            }}
   435вҶ’                          >
   436вҶ’                            {x.icon}
   437вҶ’                          </ListItemIcon>
   438вҶ’                          <ListItemText
   439вҶ’                            primary={x.name}
   440вҶ’                            sx={{
   441вҶ’                              opacity: open ? 1 : 0,
   442вҶ’                            }}
   443вҶ’                          />
   444вҶ’                        </ListItemButton>
   445вҶ’                      </Link>
   446вҶ’                    </ListItem>
   447вҶ’                  ) : x.isDivider ? (
   448вҶ’                    <Divider sx={{ my: 1 }} />
   449вҶ’                  ) : (
   450вҶ’                    <></>
   451вҶ’                  )}
   452вҶ’                </React.Fragment>
   453вҶ’              );
   454вҶ’            })}
   455вҶ’          </List>
   456вҶ’
   457вҶ’          {/* Plan Status Card */}
   458вҶ’          {planStatus.status !== null && (
   459вҶ’            <PlanStatusCard
