   500вҶ’                  router.pathname == PAGE_INFO.ACCOUNT_EDIT.href()
   501вҶ’                }
   502вҶ’                sx={{
   503вҶ’                  justifyContent: 'center',
   504вҶ’                }}
   505вҶ’              >
   506вҶ’                <ListItemIcon
   507вҶ’                  sx={{
   508вҶ’                    minWidth: 0,
   509вҶ’                    mr: open ? 3 : 'auto',
   510вҶ’                    justifyContent: 'center',
   511вҶ’                  }}
   512вҶ’                >
   513вҶ’                  <ImageOrAvatar
   514вҶ’                    url={currentUser.profile?.presignedImageUrl}
   515вҶ’                    width={40}
   516вҶ’                    height={40}
   517вҶ’                  />
   518вҶ’                </ListItemIcon>
   519вҶ’                <ListItemText
   520вҶ’                  primary={currentUser?.profile?.username ?? '-'}
   521вҶ’                  sx={{
   522вҶ’                    opacity: open ? 1 : 0,
   523вҶ’                  }}
   524вҶ’                  slotProps={{
   525вҶ’                    primary: {
   526вҶ’                      sx: {
   527вҶ’                        overflowX: 'hidden',
   528вҶ’                        textOverflow: 'ellipsis',
   529вҶ’                      },
   530вҶ’                    },
   531вҶ’                  }}
   532вҶ’                />
   533вҶ’              </ListItemButton>
   534вҶ’            </Link>
   535вҶ’          </Box>
   536вҶ’        </Drawer>
   537вҶ’        <Box
   538вҶ’          component="main"
   539вҶ’          sx={{
   540вҶ’            flexGrow: 1,
   541вҶ’            py: 2,
   542вҶ’            px: 2,
   543вҶ’            overflowX: 'auto',
   544вҶ’            minHeight: '100vh',
   545вҶ’            background: '#F9F9F9',
   546вҶ’          }}
   547вҶ’        >
   548вҶ’          {children}
   549вҶ’        </Box>
   550вҶ’      </Box>
   551вҶ’    </>
   552вҶ’  );
   553вҶ’}
   554вҶ’
   555вҶ’export default function ConsoleLayout({ children }: { children: ReactNode }) {
   556вҶ’  const { services, router } = useServicesHook();
   557вҶ’  const [_, setIsSubmitting] = useState<boolean>(false);
   558вҶ’  const currentUser = useSelector((state) => state.user.me);
   559вҶ’  const currentTeam = useSelector((state) => state.user.currentTeam);
   560вҶ’  const userError = useSelector((state) => state.user.error);
   561вҶ’  const loginStatus = useSelector((state) => state.user.loginStatus);
   562вҶ’
   563вҶ’  const logout = () => {
   564вҶ’    wrapForLoading(setIsSubmitting, async () => {
   565вҶ’      await services.default.auth.signOut();
   566вҶ’      location.href = PAGE_INFO.SIGN_IN.href();
   567вҶ’    });
   568вҶ’  };
   569вҶ’
   570вҶ’  useEffect(() => {
   571вҶ’    if (loginStatus === 'initial') {
   572вҶ’      return;
   573вҶ’    }
   574вҶ’
   575вҶ’    if (loginStatus != 'yes') {
   576вҶ’      logger.debug('SD: no user - redirect to signin');
   577вҶ’      const callbackUrl = createSafeCallbackUrl();
   578вҶ’      router.replace(`${PAGE_INFO.SIGN_IN.href()}?callbackUrl=${callbackUrl}`);
   579вҶ’    }
   580вҶ’  }, [loginStatus]);
   581вҶ’
   582вҶ’  if (loginStatus == 'error' && userError) {
   583вҶ’    return (
   584вҶ’      <>
   585вҶ’        <CriticalError error={userError} />
   586вҶ’      </>
   587вҶ’    );
   588вҶ’  }
   589вҶ’
   590вҶ’  return currentUser && currentTeam ? (
   591вҶ’    <LayoutInner currentUser={currentUser} currentTeam={currentTeam}>
   592вҶ’      {children}
   593вҶ’    </LayoutInner>
   594вҶ’  ) : currentUser ? (
   595вҶ’    <Box
   596вҶ’      sx={{
   597вҶ’        p: 2,
   598вҶ’      }}
   599вҶ’    >
   600вҶ’      <Typography>{translate('no_active_teams_found')}</Typography>
   601вҶ’      <Button color="error" sx={{ mt: 2 }} variant="contained" onClick={logout}>
   602вҶ’        {translate('sign_out')}
   603вҶ’      </Button>
   604вҶ’    </Box>
   605вҶ’  ) : (
   606вҶ’    <>
   607вҶ’      {
   608вҶ’        // nothing to do (waiting initialization)
   609вҶ’      }
   610вҶ’    </>
   611вҶ’  );
   612вҶ’}
