import CloseIcon from '@mui/icons-material/Close';
import { IconButton, Stack, Typography } from '@mui/material';
import _ from 'lodash';
import React, { FC, ReactElement, useEffect, useState } from 'react';

import { StyledLink } from '@/components/common/styled-link';
import { PAGE_INFO } from '@/constants/page.constants';
import { Team } from '@/models/team';
import { TeamTab } from '@/pages/account';
import { translate } from '@/utils/i18n';

import { InfoSvg } from '../svgs/band-icon-svgs';

export type TeamPlanLimitBandParam = {
  team: Team;
};

export const TeamPlanLimitBand: FC<TeamPlanLimitBandParam> = ({ team }) => {
  const [isOpen, setIsOpen] = useState<boolean>(true);

  const [param, setParam] = useState<{
    background: string;
    icon: ReactElement;
    text: string;
    isActive: boolean;
  }>({
    background: '',
    icon: InfoSvg,
    text: '',
    isActive: false,
  });

  useEffect(() => {
    if (team.billingFailureReason) {
      setParam({
        background: '#FF0000',
        icon: InfoSvg,
        text: translate('payment_failed'),
        isActive: true,
      });
      return;
    }

    // гғңгғјгғ«дҪҝз”ЁйҮҸгғҒгӮ§гғғгӮҜпјҲеҲ©з”ЁдёҚеҸҜгҒ®е ҙеҗҲгҒҜеҚіеә§гҒ«йҖҡзҹҘпјү
    if (!team.ballAvailability.isAvailable) {
      setParam({
        background: '#FF0000',
        icon: InfoSvg,
        text: translate(team.ballAvailability.unavailableReason!),
        isActive: true,
      });
      return;
    }

    // TeamPlan гҒ®жңҹйҷҗгғҒгӮ§гғғгӮҜпјҲitem гҒ«гӮҲгӮҠеҲ©з”ЁеҸҜиғҪгҒ§гӮӮиӯҰе‘ҠгҒҜиЎЁзӨәгҒҷгӮӢпјү
    if (!team.teamPlanAvailability.isAvailable) {
      setParam({
        background: '#FF0000',
        icon: InfoSvg,
        text: translate(team.teamPlanAvailability.unavailableReason!),
        isActive: true,
      });
      return;
    }

    const isUsageLimitApproaching = team.ballRate >= 0.9;
    const isExpirationApproaching =
      team.remainingDays <= 30 &&
      // Suppress this warning for subscription billing
      !team.teamPlan?.subscriptionType;
    if (isUsageLimitApproaching || isExpirationApproaching) {
      const texts: string[] = [];
      if (isExpirationApproaching) {
        texts.push(translate('team_plan_expiration_is_approaching'));
      }
      if (isUsageLimitApproaching) {
        texts.push(translate('usage_limit_is_approaching'));
      }
      setParam({
        background: '#FF8152',
        icon: InfoSvg,
        text: texts.join(' / '),
        isActive: true,
      });
      return;
    }

    setParam({
      background: '#000000',
      icon: InfoSvg,
      text: '',
      isActive: false,
    });
  }, [team.teamPlan, team.nextTeamPlan, team.billingFailureReason]);

  if (!isOpen || !param.isActive) {
    return '';
  }

  return (
    <Stack
      direction="row"
      sx={{ backgroundColor: param.background, color: 'white' }}
    >
      <Typography
        sx={{ alignItems: 'center', display: 'flex', flex: 1, padding: '5px' }}
        variant="body2"
      >
        {param.icon}
        <Typography
          component="span"
          sx={{ paddingLeft: '5px' }}
          variant="inherit"
        >
          {param.text}{' '}
          <StyledLink href={PAGE_INFO.ACCOUNT.href(TeamTab)} color="inherit">
            {translate('check_team_plan')}
          </StyledLink>
        </Typography>
      </Typography>
      <IconButton color="inherit" onClick={() => setIsOpen(false)}>
        <CloseIcon />
      </IconButton>
    </Stack>
  );
};

